import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("userInput");

        // Properly encoding user input before outputting it to the response
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + encodeHtml(userInput) + "</h1>"); // Encode user input before embedding it into HTML
        out.println("</body>");
        out.println("</html>");
    }

    // Function to properly encode HTML characters in user input
    private String encodeHtml(String input) {
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
